const { generateAgreementPDF } = require('./src/common/utils/agreementPdf');
const { generateAgreementId, verifyAgreementId } = require('./src/common/utils/agreementId');
const fs = require('fs');
const path = require('path');

// Sample partner data (replace with any test data you want)
const testPartnerId = '12345';
const testPartner = {
  id: BigInt(testPartnerId),
  name: 'Rahul Sharma',
  phone_number: '9876543210',
  working_city: 'Jhansi',
  serviceCategory: 'Plumbing',
  agreement_id: generateAgreementId(testPartnerId)
};

console.log('🔑 Generated agreement ID:', testPartner.agreement_id);
console.log('🔍 Self-check (untampered):', verifyAgreementId(testPartner.agreement_id));
console.log('🔍 Self-check (tampered):  ', verifyAgreementId(testPartner.agreement_id.slice(0, -1) + '0'));

// Sample base64 signature (a simple 1x1 pixel transparent PNG in base64)
// You can replace this with a real signature base64 string
const testSignatureBase64 = '';

async function testAgreementGeneration() {
  console.log('🚀 Starting PDF generation test...');
  console.log('📄 Partner details:', testPartner);
  
  try {
    const pdfBuffer = await generateAgreementPDF(testPartner, testSignatureBase64);
    
    // Save PDF to file
    const outputPath = path.join(__dirname, 'test-agreement-output.pdf');
    fs.writeFileSync(outputPath, pdfBuffer);
    
    console.log('✅ PDF generated successfully!');
    console.log(`📁 Saved to: ${outputPath}`);
    console.log(`📊 File size: ${(pdfBuffer.length / 1024).toFixed(2)} KB`);
    
  } catch (error) {
    console.error('❌ Error generating PDF:', error.message);
    console.error(error);
  }
}

// Run the test
testAgreementGeneration();